const PARAMS = {
  primaryColor: "#FF5722",     // type: color
  secondaryColor: "#FFC107",   // type: color
  speed: 1.0,                  // type: range, min: 0.1, max: 3.0
  text: "환영합니다! 😀✨",     // type: text
  fontSize: 100,               // type: range, min: 20, max: 200, unit: px
  visible: true,               // type: boolean
  animStyle: "bounce",       // type: select, options: bounce|spring|linear
  icon: "Sparkles",           // type: icon
} as const;

export const GeneratedAsset = ({
  primaryColor = PARAMS.primaryColor,
  secondaryColor = PARAMS.secondaryColor,
  speed = PARAMS.speed,
  text = PARAMS.text,
  fontSize = PARAMS.fontSize,
  visible = PARAMS.visible,
  animStyle = PARAMS.animStyle,
  icon = PARAMS.icon,
}: typeof PARAMS = PARAMS) => {
  const frame = useCurrentFrame();
  const { durationInFrames, fps, width, height } = useVideoConfig();
  const animationProgress = spring({ frame, fps, config: { damping: 10, stiffness: 100 } });

  const textOpacity = interpolate(frame, [0, 15, 135, 150], [0, 1, 1, 0], { easing: Easing.inOut(Easing.ease) });
  const bounce = interpolate(animationProgress, [0, 1], [0, -50], { extrapolate: "clamp" });

  return (
    <AbsoluteFill style={{ backgroundColor: "transparent", justifyContent: "center", alignItems: "center" }}>
      <div style={{ color: primaryColor, fontSize, opacity: textOpacity, transform: `translateY(${bounce}px)` }}>
        {text}
      </div>
    </AbsoluteFill>
  );
};

