const PARAMS = {
  primaryColor: "#FFD700", // type: color
  secondaryColor: "#1D2951", // type: color
  speed: 1.0, // type: range, min: 0.1, max: 3.0
  text: "Welcome", // type: text
  fontSize: 80, // type: range, min: 20, max: 200, unit: px
  visible: true, // type: boolean
  animStyle: "bounce", // type: select, options: bounce|spring|linear,
  icon: "Star", // type: icon
} as const;

export const GeneratedAsset = ({
  primaryColor = PARAMS.primaryColor,
  secondaryColor = PARAMS.secondaryColor,
  text = PARAMS.text,
  fontSize = PARAMS.fontSize,
  speed = PARAMS.speed
}: typeof PARAMS = PARAMS) => {
  const frame = useCurrentFrame();
  const { durationInFrames, fps, width, height } = useVideoConfig();

  // Calculate fade-in opacity
  const opacity = interpolate(frame, [0, 30], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  // Calculate bounce effect motion
  const bounce = Math.sin((frame / fps) * Math.PI * speed) * 20;

  return (
    <AbsoluteFill style={{ backgroundColor: secondaryColor }}>
      <div
        style={{
          position: "absolute",
          top: "50%",
          left: "50%",
          transform: `translate(-50%, calc(-50% + ${bounce}px))`,
          fontSize,
          color: primaryColor,
          opacity,
        }}
      >
        {text}
      </div>
    </AbsoluteFill>
  );
};

